<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#ABB2BF;">content </span><span style="--shiki-light:#D73A49;--shiki-dark:#56B6C2;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#98C379;"> &#39;(百度) www.baidu.com&#39;</span></span>
